      const newVersion = import_crypto4.default.createHash("sha256").update(content).digest("hex");
      const db7 = initDb();
      const existingAudit = db7.prepare(
        "SELECT skill_version FROM skill_audits WHERE skill_id = ? ORDER BY created_at DESC LIMIT 1"
      ).get(dirName);
