function stripTags(html) {
  return html.replace(/<[^>]*>/g, "");
}
function htmlToMarkdown(html) {
  let md = html;
  md = md.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, "");
  md = md.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, "");
  md = md.replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, "");
  md = md.replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, "");
  md = md.replace(/<header[^>]*>[\s\S]*?<\/header>/gi, "");
  md = md.replace(/<aside[^>]*>[\s\S]*?<\/aside>/gi, "");
  md = md.replace(/<h1[^>]*>([\s\S]*?)<\/h1>/gi, (_, c) => `

# ${stripTags(c)}

`);
  md = md.replace(/<h2[^>]*>([\s\S]*?)<\/h2>/gi, (_, c) => `

## ${stripTags(c)}

`);
  md = md.replace(/<h3[^>]*>([\s\S]*?)<\/h3>/gi, (_, c) => `

### ${stripTags(c)}

`);
  md = md.replace(/<h4[^>]*>([\s\S]*?)<\/h4>/gi, (_, c) => `

#### ${stripTags(c)}

`);
  md = md.replace(/<\/?(?:strong|b)[^>]*>/gi, "**");
  md = md.replace(/<\/?(?:em|i)[^>]*>/gi, "*");
  md = md.replace(/<a[^>]*href=["']([^"']*)["'][^>]*>([\s\S]*?)<\/a>/gi, "[$2]($1)");
  md = md.replace(/<code[^>]*>([\s\S]*?)<\/code>/gi, "`$1`");
  md = md.replace(/<pre[^>]*>[\s\S]*?<code[^>]*>([\s\S]*?)<\/code>[\s\S]*?<\/pre>/gi, (_, c) => `

\`\`\`
${c}
\`\`\`

`);
  md = md.replace(/<pre[^>]*>([\s\S]*?)<\/pre>/gi, (_, c) => `

\`\`\`
${stripTags(c)}
\`\`\`

`);
  md = md.replace(/<li[^>]*>([\s\S]*?)<\/li>/gi, (_, c) => `
- ${stripTags(c)}`);
  md = md.replace(/<p[^>]*>([\s\S]*?)<\/p>/gi, (_, c) => `

${stripTags(c)}

`);
  md = md.replace(/<br\s*\/?>/gi, "\n");
  md = stripTags(md);
  md = md.replace(/&amp;/g, "&");
  md = md.replace(/&lt;/g, "<");
  md = md.replace(/&gt;/g, ">");
  md = md.replace(/&quot;/g, '"');
  md = md.replace(/&#39;/g, "'");
  md = md.replace(/&nbsp;/g, " ");
  md = md.replace(/\n{3,}/g, "\n\n");
  md = md.trim();
  return md;
}
