function recommendSourceWarehouse(sku, excludeWarehouseId, suggestedQty) {
  const db7 = initDb();
  const rows = db7.prepare(`
    SELECT ii.warehouseId, ii.quantity, ii.minStock, w.name AS warehouseName
    FROM inventory_items ii
    LEFT JOIN warehouses w ON ii.warehouseId = w.id
    WHERE ii.sku = ? AND ii.warehouseId != ?
  `).all(sku, excludeWarehouseId);
  const recommendations = [];
  for (const row of rows) {
    const surplus = row.quantity - row.minStock;
    if (surplus <= 0) continue;
    const score = surplus / Math.max(1, suggestedQty);
    recommendations.push({
      warehouseId: row.warehouseId,
      warehouseName: row.warehouseName ?? row.warehouseId,
      surplus,
      score: Math.round(score * 100) / 100
    });
  }
  recommendations.sort((a, b) => b.score - a.score);
  return recommendations;
}
function getReplenishmentStats() {
  const db7 = initDb();
  const total = db7.prepare("SELECT COUNT(*) AS cnt FROM replenishment_suggestions").get();
  const pending = db7.prepare("SELECT COUNT(*) AS cnt FROM replenishment_suggestions WHERE status = 'pending'").get();
  const critical = db7.prepare("SELECT COUNT(*) AS cnt FROM replenishment_suggestions WHERE priority = 'critical' AND status = 'pending'").get();
  const inTransit = db7.prepare("SELECT COALESCE(SUM(in_transit_qty), 0) AS total FROM replenishment_suggestions WHERE status = 'pending'").get();
  const todayConfirmed = db7.prepare(
    "SELECT COUNT(*) AS cnt FROM replenishment_suggestions WHERE status = 'confirmed' AND DATE(updated_at) = DATE('now')"
  ).get();
  return {
    total: total.cnt,
    pending: pending.cnt,
    critical: critical.cnt,
    totalInTransitQty: inTransit.total,
    todayConfirmed: todayConfirmed.cnt
  };
}

