var FewShotTemplates = class {
  constructor(templates) {
    this.templates = templates ?? TEMPLATES;
  }
  /**
   * 评估用户消息，匹配最佳 Few-shot 模板。
   *
   * 匹配逻辑：
   * 1. 遍历所有模板的 triggerPatterns
   * 2. 返回第一个匹配的模板（按定义顺序，即优先级顺序）
   * 3. 无匹配返回 null
   *
   * @param userMessage - 用户消息文本
   * @returns 匹配的模板或 null
   */
  assessTrigger(userMessage) {
    const messageText = typeof userMessage === "string" ? userMessage : JSON.stringify(userMessage);
    for (const template of this.templates) {
      for (const pattern of template.triggerPatterns) {
        if (pattern.test(messageText)) {
          return template;
        }
      }
    }
    return null;
  }
  /**
   * 将 Few-shot 模板注入到消息列表中。
   * 在 system prompt 之后插入模板的 systemPrompt 和示例。
   *
   * @param messages - 原始消息列表
   * @param template - 要注入的模板
   * @returns 注入后的消息列表
   */
  injectTemplate(messages, template) {
    const result = [...messages];
    let firstSystemIdx = -1;
    for (let i = 0; i < result.length; i++) {
      if (result[i].role === "system") {
        firstSystemIdx = i;
        break;
      }
    }
    const injectedMessages = [
      {
        role: "system",
        content: `[Few-shot \u6307\u5BFC] ${template.systemPrompt}`
      },
      ...template.examples.map((ex) => ({
        role: ex.role,
        content: ex.content
      }))
    ];
    if (firstSystemIdx >= 0) {
      result.splice(firstSystemIdx + 1, 0, ...injectedMessages);
    } else {
      result.unshift(...injectedMessages);
    }
    return result;
  }
  /**
   * 获取所有模板。
   */
  getTemplates() {
    return [...this.templates];
  }
  /**
   * 根据 ID 获取模板。
   */
  getTemplateById(id) {
    return this.templates.find((t) => t.id === id);
  }
};
var fewShotTemplates = new FewShotTemplates();

// server/engine/observationCompressor.ts
var COMPRESSION_THRESHOLD = 500;
var MAX_COMPRESSED_LENGTH = 200;
var ObservationCompressor = class {
  /**
   * 压缩观察结果。
   *
   * @param result - 原始结果文本
   * @param maxLength - 压缩后最大长度（默认 200）
   * @returns 压缩后的观察结果
   */
  compress(result, maxLength = MAX_COMPRESSED_LENGTH) {
    if (result.length <= COMPRESSION_THRESHOLD) {
      return {
        compressed: result,
        original: result,
        wasCompressed: false,
        compressionRatio: 1
      };
    }
    let compressed = "";
    compressed = this.extractJsonKeyValues(result);
    if (compressed && compressed.length < result.length) {
      return this.buildResult(compressed, result, maxLength);
    }
    compressed = this.extractTableTopRows(result, 5);
    if (compressed && compressed.length < result.length) {
      return this.buildResult(compressed, result, maxLength);
    }
    compressed = this.extractTextTopParagraphs(result, 3);
    return this.buildResult(compressed, result, maxLength);
  }
  /**
   * 从 JSON 格式的结果中提取 key-value 对。
   * 保留关键字段，跳过大型数组/嵌套对象。
   *
   * @param text - 原始文本
   * @returns 提取的 key-value 摘要文本
   */
  extractJsonKeyValues(text) {
    try {
      let jsonStr = text.trim();
      const codeBlockMatch = jsonStr.match(/```(?:json)?\s*\n?([\s\S]*?)\n?```/);
      if (codeBlockMatch) {
        jsonStr = codeBlockMatch[1].trim();
      }
      const jsonStart = jsonStr.indexOf("{");
      const jsonEnd = jsonStr.lastIndexOf("}");
      if (jsonStart === -1 || jsonEnd === -1) {
        return "";
      }
      jsonStr = jsonStr.slice(jsonStart, jsonEnd + 1);
      const parsed = JSON.parse(jsonStr);
      const entries = [];
      for (const [key, value] of Object.entries(parsed)) {
        if (typeof value === "string") {
          entries.push(`${key}: ${value.length > 50 ? value.slice(0, 50) + "..." : value}`);
        } else if (typeof value === "number" || typeof value === "boolean") {
          entries.push(`${key}: ${value}`);
        } else if (Array.isArray(value)) {
          entries.push(`${key}: [${value.length} items]`);
        } else if (value === null) {
          entries.push(`${key}: null`);
        } else if (typeof value === "object") {
          const subKeys = Object.keys(value);
          entries.push(`${key}: {${subKeys.length} keys: ${subKeys.slice(0, 5).join(", ")}}`);
        }
      }
      if (entries.length === 0) {
        return "";
      }
      const result = `{${entries.join(", ")}}`;
      return result;
    } catch {
      return "";
    }
  }
  /**
   * 从表格格式的结果中提取前 N 行。
   * 识别 Markdown 表格、CSV、TSV 格式。
   *
   * @param text - 原始文本
   * @param rows - 保留的行数
   * @returns 提取的表格摘要文本
   */
  extractTableTopRows(text, rows) {
    const lines = text.split("\n").filter((line) => line.trim());
    const mdTableLines = lines.filter((line) => line.includes("|") && line.trim().startsWith("|"));
    if (mdTableLines.length >= 2) {
      const header = mdTableLines[0];
      const separator = mdTableLines[1];
      const dataRows = mdTableLines.slice(2, 2 + rows);
      const result = [header, separator, ...dataRows].join("\n");
      const totalRows = mdTableLines.length - 2;
      return `${result}
... (\u5171 ${totalRows} \u884C\uFF0C\u5DF2\u622A\u53D6\u524D ${dataRows.length} \u884C)`;
    }
    const csvLines = lines.filter(
      (line) => (line.includes(",") || line.includes("	")) && line.split(/[,\t]/).length >= 2
    );
    if (csvLines.length >= 2) {
      const header = csvLines[0];
      const dataRows = csvLines.slice(1, 1 + rows);
      const result = [header, ...dataRows].join("\n");
      return `${result}
... (\u5171 ${csvLines.length - 1} \u884C\uFF0C\u5DF2\u622A\u53D6\u524D ${dataRows.length} \u884C)`;
    }
    return "";
  }
  /**
   * 从文本结果中提取前 N 段落。
   * 按空行分段，保留最长的 N 段。
   *
   * @param text - 原始文本
   * @param count - 保留的段落数
   * @returns 提取的文本摘要
   */
  extractTextTopParagraphs(text, count) {
    const paragraphs = text.split(/\n\s*\n/).filter((p) => p.trim().length > 0);
    if (paragraphs.length <= count) {
      return text.length > MAX_COMPRESSED_LENGTH ? text.slice(0, MAX_COMPRESSED_LENGTH) + "..." : text;
    }
    const indexed = paragraphs.map((p, idx) => ({ text: p, idx, length: p.length }));
    indexed.sort((a, b) => b.length - a.length);
    const topN = indexed.slice(0, count);
    topN.sort((a, b) => a.idx - b.idx);
    const result = topN.map((item) => {
      const para = item.text.trim();
      return para.length > 80 ? para.slice(0, 80) + "..." : para;
    }).join("\n\n");
    return `${result}

... (\u539F\u59CB\u7ED3\u679C ${text.length} \u5B57\uFF0C\u5DF2\u538B\u7F29\u4E3A\u6458\u8981)`;
  }
  /**
   * 构建压缩结果对象。
   */
  buildResult(compressed, original, maxLength) {
    const finalCompressed = compressed.length > maxLength ? compressed.slice(0, maxLength) + "..." : compressed;
    return {
      compressed: finalCompressed,
      original,
      wasCompressed: true,
      compressionRatio: finalCompressed.length / original.length
    };
  }
};
function needsCompression(result, threshold = COMPRESSION_THRESHOLD) {
  return result.length > threshold;
}

